import React, { useEffect, useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

export default function CheckoutSuccess() {
    const navigate = useNavigate();
    const location = useLocation();
    const { user } = useAuth();
    const [order, setOrder] = useState(null);
    const [downloading, setDownloading] = useState(false);

    useEffect(() => {
        // Get order data from location state
        if (location.state?.order) {
            setOrder(location.state.order);
        } else {
            // If no order data, redirect to orders page
            navigate('/dashboard/orders');
        }
    }, [location.state, navigate]);

    const formatPeso = (value) => new Intl.NumberFormat('en-PH', {
        style: 'currency',
        currency: 'PHP',
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
    }).format(Number(value || 0));

    const formatDate = (date) => {
        return new Date(date).toLocaleString('en-PH');
    };

    const downloadReceipt = () => {
        if (!order) return;

        setDownloading(true);
        try {
            const lines = [];
            lines.push('╔════════════════════════════════════════╗');
            lines.push('║           CARVEX RECEIPT              ║');
            lines.push('╚════════════════════════════════════════╝');
            lines.push('');
            lines.push(`ORDER NUMBER: ${order.order_number || order.id}`);
            lines.push(`DATE: ${formatDate(order.created_at)}`);
            lines.push('');
            lines.push('────────────────────────────────────────');
            lines.push('CUSTOMER INFORMATION');
            lines.push('────────────────────────────────────────');
            lines.push(`Name: ${user?.name || 'N/A'}`);
            lines.push(`Email: ${user?.email || 'N/A'}`);
            lines.push(`Phone: ${user?.phone || 'N/A'}`);
            lines.push('');
            lines.push('────────────────────────────────────────');
            lines.push('DELIVERY ADDRESS');
            lines.push('────────────────────────────────────────');
            lines.push(order.shipping_address || 'N/A');
            lines.push('');
            lines.push('────────────────────────────────────────');
            lines.push('PAYMENT INFORMATION');
            lines.push('────────────────────────────────────────');
            lines.push(`Payment Method: ${(order.payment_method || 'cod').toUpperCase()}`);
            lines.push(`Payment Status: ${order.payment_status || 'PENDING'}`);
            lines.push('');
            lines.push('────────────────────────────────────────');
            lines.push('ORDER SUMMARY');
            lines.push('────────────────────────────────────────');
            lines.push(`Subtotal:        ${formatPeso(order.subtotal || 0)}`);
            lines.push(`Shipping:        ${formatPeso(order.shipping || 0)}`);
            lines.push(`Tax (10%):       ${formatPeso(order.tax || 0)}`);
            lines.push('────────────────────────────────────────');
            lines.push(`TOTAL:           ${formatPeso(order.total_amount || order.total || 0)}`);
            lines.push('────────────────────────────────────────');
            lines.push('');
            lines.push('STATUS: ' + (order.status || 'PROCESSING').toUpperCase());
            lines.push('');
            lines.push('Thank you for your purchase!');
            lines.push('');
            lines.push('For tracking updates, visit: /dashboard/orders');
            lines.push('');
            lines.push('Generated: ' + new Date().toLocaleString());

            const blob = new Blob([lines.join('\n')], { type: 'text/plain;charset=utf-8' });
            const url = window.URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `carvex-receipt-${order.order_number || order.id}.txt`;
            document.body.appendChild(link);
            link.click();
            link.remove();
            window.URL.revokeObjectURL(url);
        } finally {
            setDownloading(false);
        }
    };

    if (!order) {
        return null;
    }

    return (
        <section className="checkout-success-page">
            <div className="checkout-success-container">
                <div className="checkout-success-icon">
                    <svg viewBox="0 0 24 24" width="34" height="34" fill="none" stroke="currentColor" strokeWidth="2">
                        <polyline points="20 6 9 17 4 12" />
                    </svg>
                </div>

                <h1>Order Placed Successfully!</h1>
                <p className="checkout-success-subtitle">Thank you for your purchase. Your order has been confirmed.</p>

                <div className="checkout-success-receipt">
                    <div className="receipt-section">
                        <div className="receipt-label">Order Number</div>
                        <div className="receipt-value">{order.order_number || `#${order.id}`}</div>
                    </div>

                    <div className="receipt-section">
                        <div className="receipt-label">Order Date</div>
                        <div className="receipt-value">{formatDate(order.created_at)}</div>
                    </div>

                    <div className="receipt-divider" />

                    <div className="receipt-section">
                        <div className="receipt-label">Shipping Address</div>
                        <div className="receipt-value receipt-value--address">{order.shipping_address}</div>
                    </div>

                    <div className="receipt-divider" />

                    <div className="receipt-section">
                        <div className="receipt-label">Payment Method</div>
                        <div className="receipt-value">{(order.payment_method || 'cod').toUpperCase()}</div>
                    </div>

                    <div className="receipt-section">
                        <div className="receipt-label">Payment Status</div>
                        <div className={`receipt-value receipt-status receipt-status--${order.payment_status || 'pending'}`}>
                            {order.payment_status ? order.payment_status.charAt(0).toUpperCase() + order.payment_status.slice(1) : 'Pending'}
                        </div>
                    </div>

                    <div className="receipt-divider" />

                    <div className="receipt-section">
                        <div className="receipt-label">Subtotal</div>
                        <div className="receipt-value">{formatPeso(order.subtotal || 0)}</div>
                    </div>

                    <div className="receipt-section">
                        <div className="receipt-label">Shipping</div>
                        <div className="receipt-value">{formatPeso(order.shipping || 0)}</div>
                    </div>

                    <div className="receipt-section">
                        <div className="receipt-label">Tax (10%)</div>
                        <div className="receipt-value">{formatPeso(order.tax || 0)}</div>
                    </div>

                    <div className="receipt-divider" />

                    <div className="receipt-section receipt-section--total">
                        <div className="receipt-label">Total Amount</div>
                        <div className="receipt-value receipt-value--total">{formatPeso(order.total_amount || order.total || 0)}</div>
                    </div>

                    <div className="receipt-status-box">
                        <strong>Order Status:</strong> {(order.status || 'Processing').toUpperCase()}
                    </div>
                </div>

                <div className="checkout-success-actions">
                    <button
                        type="button"
                        className="btn btn-primary btn-lg"
                        onClick={downloadReceipt}
                        disabled={downloading}
                    >
                        {downloading ? 'Downloading...' : 'Download Receipt'}
                    </button>

                    <button
                        type="button"
                        className="btn btn-outline-primary btn-lg"
                        onClick={() => navigate('/dashboard/orders')}
                    >
                        Track Your Order
                    </button>

                    <button
                        type="button"
                        className="btn btn-outline-primary btn-lg"
                        onClick={() => navigate('/dashboard/products')}
                    >
                        Continue Shopping
                    </button>
                </div>

                <div className="checkout-success-help">
                    <p>Need help? <a href="/customer-service">Contact Support</a></p>
                </div>
            </div>
        </section>
    );
}
